// DEPRECATED: Echo logic is now handled by Router workflow
// This workflow remains for backwards compatibility and direct testing
//
// The Router workflow now:
// 1. Checks if message is incoming (dataType === 'message_create' && !fromMe)
// 2. Sends echo reply directly via wwebjs-api
//
// This endpoint can be used for testing webhook reception

const input = $input.first();
const webhookData = input.json;
const body = webhookData.body || webhookData;
const data = body.data || {};
const message = data.message || data || {};

return [{
  json: {
    deprecated: true,
    note: 'Echo functionality moved to Router workflow',
    received: {
      dataType: body.dataType || null,
      sessionId: body.sessionId || null,
      from: message.from || null,
      messageBody: message.body || null,
      timestamp: new Date().toISOString()
    }
  }
}];
